esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.znode.count IS NOT NULL
// Peak znode count per node in the time window
| STATS max_znodes = MAX(metrics.zookeeper.znode.count) BY host.name
// Official ZooKeeper docs recommend alerting above 1,000,000 znodes
// Excessive znodes cause memory pressure and slow startup/recovery
// Adjust based on your expected data model size
| WHERE max_znodes > 1000000
